import React from "react";
import { Link } from "react-router-dom";
import Navbar from "../components/Navbar";

const Home = () => {
  const listings = [
    {
      id: 1,
      title: "Beachfront Paradise",
      location: "Goa, India",
      price: "₹8,000/night",
      image:
        "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?fit=crop&w=800&q=80",
    },
    {
      id: 2,
      title: "Mountain Escape",
      location: "Manali, India",
      price: "₹6,000/night",
      image:
        "https://images.unsplash.com/photo-1501785888041-af3ef285b470?fit=crop&w=800&q=80",
    },
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />

      {/* Hero Section */}
      <section className="text-center py-20 bg-gradient-to-r from-pink-500 to-rose-500 text-white">
        <h1 className="text-5xl font-bold mb-4">Find Your Next Getaway</h1>
        <p className="text-lg mb-6">Book beautiful homes and experiences worldwide 🌎</p>

        {/* Search Bar */}
        <div className="flex justify-center">
          <div className="flex bg-white rounded-full shadow-lg p-2 w-[80%] sm:w-[60%] md:w-[40%]">
            <input
              type="text"
              placeholder="Search destinations..."
              className="flex-grow px-4 py-2 rounded-l-full focus:outline-none text-gray-700"
            />
            <button className="bg-pink-500 hover:bg-pink-600 text-white px-5 py-2 rounded-full transition-all">
              🔍 Search
            </button>
          </div>
        </div>
      </section>

      {/* Listings Section */}
      <section className="px-6 py-12 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 max-w-6xl mx-auto">
        {listings.map((listing) => (
          <div
            key={listing.id}
            className="bg-white rounded-2xl shadow-lg hover:shadow-2xl transition-all overflow-hidden"
          >
            <img
              src={listing.image}
              alt={listing.title}
              className="h-56 w-full object-cover"
            />
            <div className="p-5 text-left">
              <h3 className="text-xl font-semibold text-gray-800">{listing.title}</h3>
              <p className="text-gray-500">{listing.location}</p>
              <p className="text-pink-600 font-bold mt-2">{listing.price}</p>

              <Link
                to="/bookingconfirmation"
                state={{ listing }}
                className="mt-4 inline-block w-full text-center bg-gradient-to-r from-pink-500 to-rose-500 text-white py-2 rounded-lg font-medium hover:from-rose-600 hover:to-pink-600 transition-all duration-300"
              >
                Book Now
              </Link>
            </div>
          </div>
        ))}
      </section>
    </div>
  );
};

export default Home;
